		persons.clear();
		firms.clear();
		timedData.clear();
		tempData.clear();
		serverData.clear();
		save();
		// Reload the PLUGIN
		Bukkit.getServer().getPluginManager().disablePlugin(Capitalism.PLUGIN);
		Bukkit.getServer().getPluginManager().enablePlugin(Capitalism.PLUGIN);
	}
	/*
